import React, { useEffect, useMemo, useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  acceptDispatch,
  completeDispatch,
  getMyAmbulance,
  getMyDispatches,
  registerAmbulance,
  rejectDispatch,
  updateAmbulanceLocation,
  updateAmbulanceStatus,
} from "../../service/apiservice";
import { connectSocket, disconnectSocket } from "../../service/socketService";
import { clearAuth, getStoredUser } from "../../utils/auth";
import "./Counselor.css";

const AmbulanceDashboard = () => {
  const navigate = useNavigate();
  const user = useMemo(() => getStoredUser(), []);

  const [ambulance, setAmbulance] = useState(null);
  const [dispatches, setDispatches] = useState([]);
  const [form, setForm] = useState({ driverName: "", vehicleNumber: "", lat: "", lng: "" });
  const [error, setError] = useState("");

  const load = async () => {
    try {
      const [ambRes, disRes] = await Promise.all([getMyAmbulance(), getMyDispatches()]);
      setAmbulance(ambRes.ambulance || null);
      setDispatches(disRes.dispatches || []);
    } catch (err) {
      setError(err.message || "Failed to load ambulance data");
    }
  };

  useEffect(() => {
    load();
    const socket = connectSocket();
    socket.on("dispatch:assigned", () => load());
    return () => {
      socket.off("dispatch:assigned");
      disconnectSocket();
    };
  }, []);

  const logout = () => {
    clearAuth();
    navigate("/login");
  };

  const submitRegistration = async (e) => {
    e.preventDefault();
    setError("");
    try {
      const payload = {
        driverName: form.driverName,
        vehicleNumber: form.vehicleNumber,
        location: { lat: Number(form.lat || 0), lng: Number(form.lng || 0) },
        availabilityStatus: "Offline",
      };
      await registerAmbulance(payload);
      await load();
    } catch (err) {
      setError(err.message || "Registration failed");
    }
  };

  const updateStatus = async (status) => {
    await updateAmbulanceStatus(status);
    load();
  };

  const updateLocation = async () => {
    const lat = Number(prompt("Latitude", ambulance?.location?.lat ?? 0));
    const lng = Number(prompt("Longitude", ambulance?.location?.lng ?? 0));
    if (Number.isNaN(lat) || Number.isNaN(lng)) return;
    await updateAmbulanceLocation({ lat, lng });
    load();
  };

  const onAccept = async (dispatchId) => {
    await acceptDispatch(dispatchId);
    load();
  };

  const onReject = async (dispatchId) => {
    const reason = prompt("Reason for rejection", "Unit unavailable") || "Unit unavailable";
    await rejectDispatch(dispatchId, reason);
    load();
  };

  const onComplete = async (dispatchId) => {
    await completeDispatch(dispatchId);
    load();
  };

  if (!ambulance) {
    return (
      <div className="amb-page">
        <header>
          <h2>Ambulance Provider Setup</h2>
          <button onClick={logout}>Logout</button>
        </header>
        <form className="setup-card" onSubmit={submitRegistration}>
          <input placeholder="Driver name" value={form.driverName} onChange={(e) => setForm({ ...form, driverName: e.target.value })} required />
          <input placeholder="Vehicle number" value={form.vehicleNumber} onChange={(e) => setForm({ ...form, vehicleNumber: e.target.value })} required />
          <input placeholder="Latitude" value={form.lat} onChange={(e) => setForm({ ...form, lat: e.target.value })} />
          <input placeholder="Longitude" value={form.lng} onChange={(e) => setForm({ ...form, lng: e.target.value })} />
          {error && <p className="error-text">{error}</p>}
          <button type="submit">Register Ambulance Unit</button>
        </form>
      </div>
    );
  }

  return (
    <div className="amb-page">
      <header>
        <div>
          <h2>Ambulance Dashboard</h2>
          <p>{user?.name} ({user?.email})</p>
        </div>
        <button onClick={logout}>Logout</button>
      </header>

      <section className="amb-card">
        <h3>Unit Profile</h3>
        <p>Driver: {ambulance.driverName}</p>
        <p>Vehicle: {ambulance.vehicleNumber}</p>
        <p>Verification: {ambulance.verificationStatus}</p>
        <p>Status: {ambulance.availabilityStatus}</p>
        <div className="row-actions">
          <button onClick={() => updateStatus("Available")}>Available</button>
          <button onClick={() => updateStatus("Busy")}>Busy</button>
          <button onClick={() => updateStatus("Offline")}>Offline</button>
          <button onClick={updateLocation}>Update Location</button>
        </div>
      </section>

      <section className="amb-card">
        <h3>Dispatch Requests</h3>
        <table>
          <thead>
            <tr>
              <th>Assigned</th>
              <th>Status</th>
              <th>Severity</th>
              <th>Action</th>
            </tr>
          </thead>
          <tbody>
            {dispatches.map((d) => (
              <tr key={d._id}>
                <td>{new Date(d.assignedTime).toLocaleString()}</td>
                <td>{d.status}</td>
                <td>{d.accidentId?.severity || "-"}</td>
                <td>
                  {d.status === "Assigned" && (
                    <>
                      <button onClick={() => onAccept(d._id)}>Accept</button>
                      <button onClick={() => onReject(d._id)}>Reject</button>
                    </>
                  )}
                  {d.status === "Accepted" && <button onClick={() => onComplete(d._id)}>Complete</button>}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </div>
  );
};

export default AmbulanceDashboard;
